import{c as a,Q as o,j as t,m as r}from"./chunks/framework.BXc4yaFE.js";const g=JSON.parse('{"title":"🔓 The Decoder — 2026-05-28","description":"","frontmatter":{},"headers":[],"relativePath":"research/ai-news/2026-05/2026-05-28-the-decoder.md","filePath":"research/ai-news/2026-05/2026-05-28-the-decoder.md","lastUpdated":1779935873000}'),n={name:"research/ai-news/2026-05/2026-05-28-the-decoder.md"};function i(s,e,l,d,h,c){return o(),t("div",null,[...e[0]||(e[0]=[r('<h1 id="🔓-the-decoder-—-2026-05-28" tabindex="-1">🔓 The Decoder — 2026-05-28 <a class="header-anchor" href="#🔓-the-decoder-—-2026-05-28" aria-label="Permalink to &quot;🔓 The Decoder — 2026-05-28&quot;">​</a></h1><blockquote><p>企業 AI 開發與模型應用日報，涵蓋 AI 社會影響（英語媒體） 來源：<a href="https://the-decoder.com/feed/" target="_blank" rel="noreferrer">The Decoder</a></p></blockquote><hr><h2 id="microsoft-s-mai-image-2-5-pulls-even-with-google-s-nano-banana-2-on-benchmarks" tabindex="-1"><a href="https://the-decoder.com/microsofts-mai-image-2-5-pulls-even-with-googles-nano-banana-2-on-benchmarks/" target="_blank" rel="noreferrer">Microsoft&#39;s MAI-Image-2.5 pulls even with Google&#39;s Nano Banana 2 on benchmarks</a> <a class="header-anchor" href="#microsoft-s-mai-image-2-5-pulls-even-with-google-s-nano-banana-2-on-benchmarks" aria-label="Permalink to &quot;[Microsoft&#39;s MAI-Image-2.5 pulls even with Google&#39;s Nano Banana 2 on benchmarks](https://the-decoder.com/microsofts-mai-image-2-5-pulls-even-with-googles-nano-banana-2-on-benchmarks/)&quot;">​</a></h2><p><em>🔓 The Decoder | 2026-05-27</em></p><p>Microsoft&#39;s MAI-Image-2.5 ranks third on Arena&#39;s text-to-image leaderboard, on par with Google&#39;s Nano Banana 2 but still behind OpenAI&#39;s Image-2. The model shows clear gains over its predecessor, especially in rendering text inside images and commercial visuals.</p><p>The article <a href="https://the-decoder.com/microsofts-mai-image-2-5-pulls-even-with-googles-nano-banana-2-on-benchmarks/" target="_blank" rel="noreferrer">Microsoft&#39;s MAI-Image-2.5 pulls even with Google&#39;s Nano Banana 2 on benchmarks</a> appeared first on <a href="https://the-decoder.com" target="_blank" rel="noreferrer">The Decoder</a>.</p><hr><h2 id="ai-coding-agent-devin-maker-cognition-more-than-doubles-its-valuation-to-26-billion-in-under-nine-months" tabindex="-1"><a href="https://the-decoder.com/ai-coding-agent-devin-maker-cognition-more-than-doubles-its-valuation-to-26-billion-in-under-nine-months/" target="_blank" rel="noreferrer">AI coding agent Devin maker Cognition more than doubles its valuation to $26 billion in under nine months</a> <a class="header-anchor" href="#ai-coding-agent-devin-maker-cognition-more-than-doubles-its-valuation-to-26-billion-in-under-nine-months" aria-label="Permalink to &quot;[AI coding agent Devin maker Cognition more than doubles its valuation to $26 billion in under nine months](https://the-decoder.com/ai-coding-agent-devin-maker-cognition-more-than-doubles-its-valuation-to-26-billion-in-under-nine-months/)&quot;">​</a></h2><p><em>🔓 The Decoder | 2026-05-27</em></p><p>Cognition, the company behind AI software developer Devin, has raised over $1 billion at a valuation north of $26 billion. The massive round shows just how much investor money is flowing into AI coding agents, even as their real-world value remains hotly debated.</p><p>The article <a href="https://the-decoder.com/ai-coding-agent-devin-maker-cognition-more-than-doubles-its-valuation-to-26-billion-in-under-nine-months/" target="_blank" rel="noreferrer">AI coding agent Devin maker Cognition more than doubles its valuation to $26 billion in under nine months</a> appeared first on <a href="https://the-decoder.com" target="_blank" rel="noreferrer">The Decoder</a>.</p><hr><h2 id="robinhood-lets-ai-agents-trade-shares-and-make-credit-card-purchases-for-customers" tabindex="-1"><a href="https://the-decoder.com/robinhood-lets-ai-agents-trade-shares-and-make-credit-card-purchases-for-customers/" target="_blank" rel="noreferrer">Robinhood lets AI agents trade shares and make credit card purchases for customers</a> <a class="header-anchor" href="#robinhood-lets-ai-agents-trade-shares-and-make-credit-card-purchases-for-customers" aria-label="Permalink to &quot;[Robinhood lets AI agents trade shares and make credit card purchases for customers](https://the-decoder.com/robinhood-lets-ai-agents-trade-shares-and-make-credit-card-purchases-for-customers/)&quot;">​</a></h2><p><em>🔓 The Decoder | 2026-05-27</em></p><p>Robinhood now lets customers connect AI agents like Anthropic&#39;s Claude to a separate investment account via MCP. The agents can trade stocks on their own. US brokerage regulator FINRA already flags such agents as a new risk area, warning about unchecked decisions. Robinhood itself admits the product isn&#39;t for everyone.</p><p>The article <a href="https://the-decoder.com/robinhood-lets-ai-agents-trade-shares-and-make-credit-card-purchases-for-customers/" target="_blank" rel="noreferrer">Robinhood lets AI agents trade shares and make credit card purchases for customers</a> appeared first on <a href="https://the-decoder.com" target="_blank" rel="noreferrer">The Decoder</a>.</p><hr><h2 id="youtube-will-try-to-automatically-flag-ai-videos-starting-this-month" tabindex="-1"><a href="https://the-decoder.com/youtube-will-try-to-automatically-flag-ai-videos-starting-this-month/" target="_blank" rel="noreferrer">YouTube will try to automatically flag AI videos starting this month</a> <a class="header-anchor" href="#youtube-will-try-to-automatically-flag-ai-videos-starting-this-month" aria-label="Permalink to &quot;[YouTube will try to automatically flag AI videos starting this month](https://the-decoder.com/youtube-will-try-to-automatically-flag-ai-videos-starting-this-month/)&quot;">​</a></h2><p><em>🔓 The Decoder | 2026-05-27</em></p><p>YouTube is tightening its AI labeling rules. Labels for photorealistic or heavily AI-altered content will now show up in more visible spots, below the player for long videos and as an overlay on Shorts. Starting May 2026, an automatic detection system will flag AI-generated content even if creators don&#39;t disclose it. Recommendations and monetization won&#39;t be affected.</p><p>The article <a href="https://the-decoder.com/youtube-will-try-to-automatically-flag-ai-videos-starting-this-month/" target="_blank" rel="noreferrer">YouTube will try to automatically flag AI videos starting this month</a> appeared first on <a href="https://the-decoder.com" target="_blank" rel="noreferrer">The Decoder</a>.</p><hr><h2 id="the-ai-boom-drove-nvidia-s-yearly-taiwan-spending-from-15-billion-to-150-billion" tabindex="-1"><a href="https://the-decoder.com/the-ai-boom-drove-nvidias-yearly-taiwan-spending-from-15-billion-to-150-billion/" target="_blank" rel="noreferrer">The AI boom drove Nvidia&#39;s yearly Taiwan spending from $15 billion to $150 billion</a> <a class="header-anchor" href="#the-ai-boom-drove-nvidia-s-yearly-taiwan-spending-from-15-billion-to-150-billion" aria-label="Permalink to &quot;[The AI boom drove Nvidia&#39;s yearly Taiwan spending from $15 billion to $150 billion](https://the-decoder.com/the-ai-boom-drove-nvidias-yearly-taiwan-spending-from-15-billion-to-150-billion/)&quot;">​</a></h2><p><em>🔓 The Decoder | 2026-05-27</em></p><p>Nvidia now spends up to $150 billion a year on suppliers like TSMC in Taiwan.</p><p>The article <a href="https://the-decoder.com/the-ai-boom-drove-nvidias-yearly-taiwan-spending-from-15-billion-to-150-billion/" target="_blank" rel="noreferrer">The AI boom drove Nvidia&#39;s yearly Taiwan spending from $15 billion to $150 billion</a> appeared first on <a href="https://the-decoder.com" target="_blank" rel="noreferrer">The Decoder</a>.</p><hr>',28)])])}const b=a(n,[["render",i]]);export{g as __pageData,b as default};
